// Extrai TODOS os clientes e suas lojas em uma lista plana
const items = [];

for (const cliente of $input.all()) {
  const lojas = cliente.json.lojas || [];

  // Se lojas vier como string (JSON), parsear
  const lojasArray = typeof lojas === 'string' ? JSON.parse(lojas) : lojas;

  for (const loja of lojasArray) {
    items.push({
      json: {
        // Dados do cliente
        empresa_id: cliente.json.empresa_id,
        nome_cliente: cliente.json.nome_cliente,
        api_url: cliente.json.api_url,
        api_endpoint: cliente.json.api_endpoint || '/consultapedidovenda',

        // Dados da loja
        loja_id: loja.loja_id,
        codigo_loja: loja.codigo,
        nome_loja: loja.nome
      }
    });
  }
}

return items;

